/**
 * Variable type configuration and helper functions
 *
 * With the simplified variable model, type is now derived from the variable ID and value:
 *
 * Keygroups (ID prefix):
 *   /var/*      - Shared config (plaintext, NOT encrypted) -> "config"
 *   /dev/*      - Dev secrets (encrypted) -> "secret" if ref+sops, else "config"
 *   /staging/*  - Staging secrets (encrypted) -> "secret" if ref+sops, else "config"
 *   /prod/*     - Production secrets (encrypted) -> "secret" if ref+sops, else "config"
 *   /computed/* - Generated by Nix (read-only) -> "computed" or "service"
 *
 * Value patterns (vals backend):
 *   ref+sops://...  -> "secret" (encrypted SOPS file)
 *   ref+yaml://...  -> "config" (plaintext YAML file)
 *   ref+*://...     -> "computed" (other vals references like awsssm, vault)
 *   literal string  -> "config"
 *
 * Chamber backend:
 *   When backend=chamber, any variable in an encrypted keygroup (/dev, /staging, /prod)
 *   is a "secret" regardless of value pattern. Chamber stores secrets as plain values
 *   in AWS SSM Parameter Store and handles encryption transparently.
 */

import { Key, Server, Settings, Sparkles } from "lucide-react";

export const VARIABLE_TYPES = [
  {
    value: "secret",
    label: "Secret",
    description: "Sensitive value stored encrypted",
    icon: Key,
    color: "bg-red-500/20 text-red-400",
    readonly: false,
  },
  {
    value: "config",
    label: "Config",
    description: "Non-sensitive configuration",
    icon: Settings,
    color: "bg-blue-500/20 text-blue-400",
    readonly: false,
  },
  {
    value: "computed",
    label: "Computed",
    description: "Derived from other config",
    icon: Sparkles,
    color: "bg-purple-500/20 text-purple-400",
    readonly: true,
  },
  {
    value: "service",
    label: "Service",
    description: "Auto-generated from service",
    icon: Server,
    color: "bg-green-500/20 text-green-400",
    readonly: true,
  },
] as const;

export type VariableTypeName = (typeof VARIABLE_TYPES)[number]["value"];

/** Variables backend type */
export type VariablesBackend = "vals" | "chamber";

/**
 * Determine variable type from ID and value.
 *
 * Type derivation (vals backend):
 * 1. ID starts with /computed/services/ -> "service" (read-only)
 * 2. ID starts with /computed/ -> "computed" (read-only)
 * 3. ID starts with /var/ -> "config" (plaintext, shared config)
 * 4. Value is ref+sops://... -> "secret" (encrypted)
 * 5. Value is ref+yaml://... -> "config" (plaintext YAML reference)
 * 6. Value is ref+*://... -> "computed" (external vals reference)
 * 7. Otherwise -> "config" (literal value)
 *
 * Type derivation (chamber backend):
 * Steps 1-3 are the same.
 * 4. Any variable in an encrypted keygroup (/dev, /staging, /prod) -> "secret"
 * 5. Otherwise -> "config" (literal value)
 *
 * @param id - Variable ID path (e.g., "/dev/DATABASE_URL")
 * @param value - Variable value
 * @param backend - Variables backend ("vals" or "chamber"). Defaults to "vals".
 */
export function getVariableType(
  id: string,
  value: string,
  backend: VariablesBackend = "vals",
): VariableTypeName {
  // Computed variables from Nix (read-only)
  if (id.startsWith("/computed/services/")) {
    return "service";
  }
  if (id.startsWith("/computed/")) {
    return "computed";
  }

  // Shared config variables (plaintext, /var/* keygroup)
  if (id.startsWith("/var/")) {
    return "config";
  }

  // Chamber backend: any variable in an encrypted keygroup is a secret
  if (backend === "chamber") {
    const keyGroup = getKeyGroup(id);
    if (isEncryptedKeyGroup(keyGroup)) {
      return "secret";
    }
    return "config";
  }

  // Vals backend: check value for vals references
  if (value.startsWith("ref+sops://")) {
    return "secret";
  }
  if (value.startsWith("ref+yaml://") || value.startsWith("ref+file://")) {
    return "config"; // Plaintext file references
  }
  if (value.startsWith("ref+")) {
    return "computed"; // Other vals references (awsssm, vault, etc.)
  }

  // Vals backend: AGE-encrypted secrets have empty or non-reference values
  // but live in encrypted keygroups. Classify by keygroup.
  const keyGroup = getKeyGroup(id);
  if (isEncryptedKeyGroup(keyGroup)) {
    return "secret";
  }

  // Default to config for literal values in non-encrypted keygroups
  return "config";
}

/**
 * Get type config from type name or by analyzing id/value.
 *
 * @param typeOrId - Either a type name ("secret") or a variable ID ("/dev/FOO")
 * @param value - Variable value (only used when typeOrId is an ID)
 * @param backend - Variables backend. Defaults to "vals".
 */
export function getTypeConfig(
  typeOrId: VariableTypeName | string,
  value?: string,
  backend: VariablesBackend = "vals",
) {
  // If we have both id and value, derive the type
  if (value !== undefined && typeOrId.startsWith("/")) {
    const typeName = getVariableType(typeOrId, value, backend);
    return (
      VARIABLE_TYPES.find((t) => t.value === typeName) ?? VARIABLE_TYPES[1]
    );
  }

  // Otherwise treat as type name
  const typeStr =
    typeof typeOrId === "string" ? typeOrId.toLowerCase() : "config";
  return VARIABLE_TYPES.find((t) => t.value === typeStr) ?? VARIABLE_TYPES[1];
}

/**
 * Check if a variable is read-only based on its ID.
 */
export function isReadOnlyVariable(id: string): boolean {
  return id.startsWith("/computed/");
}

/**
 * Extract keygroup from variable ID.
 * e.g., "/dev/DATABASE_URL" -> "dev"
 * e.g., "/computed/apps/web/port" -> "computed"
 */
export function getKeyGroup(id: string): string {
  const match = id.match(/^\/([^/]+)\//);
  return match?.[1] ?? "dev";
}

/**
 * Extract variable name from ID.
 * e.g., "/dev/DATABASE_URL" -> "DATABASE_URL"
 * e.g., "/computed/apps/web/port" -> "port"
 */
export function getVariableName(id: string): string {
  const parts = id.split("/");
  return parts[parts.length - 1] ?? id;
}

/**
 * Validate a secret key name follows Chamber naming rules:
 * lowercase alphanumeric + hyphens only, must start with alphanumeric.
 */
const SECRET_KEY_PATTERN = /^[a-z0-9][a-z0-9-]*$/;

export function isValidSecretKey(key: string): boolean {
  return SECRET_KEY_PATTERN.test(key);
}

export function formatSecretKeyError(key: string): string | null {
  if (!key) return "Key is required";
  if (/[A-Z]/.test(key))
    return `Key "${key}" contains uppercase letters. Use lowercase only (e.g., "${key.toLowerCase()}")`;
  if (/\//.test(key))
    return `Key "${key}" contains slashes. Use hyphens instead`;
  if (!SECRET_KEY_PATTERN.test(key))
    return `Key "${key}" is invalid. Use only lowercase letters, numbers, and hyphens (must start with a letter or number)`;
  return null;
}

/**
 * Check if a value is a vals reference.
 */
export function isValsReference(value: string): boolean {
  return value.startsWith("ref+");
}

/**
 * Check if a value is a SOPS secret reference.
 */
export function isSopsReference(value: string): boolean {
  return value.startsWith("ref+sops://");
}

/**
 * Backend-aware check: is this variable a secret?
 *
 * - vals backend: secret if value starts with `ref+sops://`
 * - chamber backend: secret if the ID is in an encrypted keygroup
 */
export function isSecretVariable(
  id: string,
  value: string,
  backend: VariablesBackend = "vals",
): boolean {
  return getVariableType(id, value, backend) === "secret";
}

/**
 * Known keygroups and their characteristics.
 */
export const KEYGROUPS = {
  var: {
    label: "Shared",
    encrypted: false,
    description: "Plaintext shared config",
  },
  dev: { label: "Dev", encrypted: true, description: "Development secrets" },
  staging: {
    label: "Staging",
    encrypted: true,
    description: "Staging secrets",
  },
  prod: { label: "Prod", encrypted: true, description: "Production secrets" },
  computed: {
    label: "Computed",
    encrypted: false,
    description: "Generated by Nix (read-only)",
  },
} as const;

export type KeyGroupName = keyof typeof KEYGROUPS;

/**
 * Check if a keygroup stores encrypted secrets.
 */
export function isEncryptedKeyGroup(keyGroup: string): boolean {
  const kg = KEYGROUPS[keyGroup as KeyGroupName];
  return kg?.encrypted ?? false;
}

/**
 * Get the SOPS file path for a keygroup.
 * Returns null for non-SOPS keygroups (var, computed).
 */
export function getSopsFilePath(keyGroup: string): string | null {
  if (keyGroup === "var" || keyGroup === "computed") {
    return null;
  }
  return `.stackpanel/secrets/vars/${keyGroup}.sops.yaml`;
}

/**
 * Build a SOPS reference for a secret.
 */
export function buildSopsReference(keyGroup: string, key: string): string {
  return `ref+sops://.stackpanel/secrets/vars/${keyGroup}.sops.yaml#/${key}`;
}

/**
 * Build a YAML reference for a plaintext config value.
 */
export function buildYamlReference(key: string): string {
  return `ref+yaml://.stackpanel/secrets/vars/var.sops.yaml#/${key}`;
}

// =============================================================================
// Group-based secrets helpers (new architecture)
// =============================================================================

/**
 * Build a group-based SOPS reference for the DEPLOYED env package.
 * Uses relative paths that work when running from packages/env/data/
 * Format: ref+sops://vars/<group>.sops.yaml#/<key>
 *
 * For source project references (which use the configured secrets-dir),
 * use the valsRef returned from the API instead of building it client-side.
 */
export function buildGroupSopsReference(group: string, key: string): string {
  // Relative path for deployed env package
  return `ref+sops://vars/${group}.sops.yaml#/${key}`;
}

/**
 * Build a source project SOPS reference (when secretsDir is known).
 * This should generally NOT be used - prefer the API-returned valsRef.
 */
export function buildSourceGroupSopsReference(
  secretsDir: string,
  group: string,
  key: string,
): string {
  return `ref+sops://${secretsDir}/vars/${group}.sops.yaml#/${key}`;
}

/**
 * Check if a value is a group-based SOPS reference.
 * Matches both source project refs and env package refs:
 * - ref+sops://.stackpanel/secrets/vars/<group>.sops.yaml#/<key>
 * - ref+sops://vars/<group>.sops.yaml#/<key>
 */
export function isGroupSopsReference(value: string): boolean {
  return (
    value.startsWith("ref+sops://vars/") ||
    (value.includes("/vars/") && value.startsWith("ref+sops://"))
  );
}

/**
 * Parse a group-based SOPS reference to extract group and key.
 * Handles both source project refs and env package refs.
 * Returns null if the value is not a valid group reference.
 *
 * @example
 * parseGroupSopsReference("ref+sops://.stackpanel/secrets/vars/dev.sops.yaml#/DATABASE_URL")
 * // Returns: { group: "dev", key: "DATABASE_URL" }
 *
 * @example
 * parseGroupSopsReference("ref+sops://vars/dev.sops.yaml#/DATABASE_URL")
 * // Returns: { group: "dev", key: "DATABASE_URL" }
 */
export function parseGroupSopsReference(
  value: string,
): { group: string; key: string } | null {
  // Try env package format first: ref+sops://vars/<group>.sops.yaml#/<key>
  let match = value.match(
    /^ref\+sops:\/\/vars\/([^.]+)\.sops\.yaml#\/(.+)$/,
  );
  if (match) {
    return { group: match[1], key: match[2] };
  }

  // Try source project format: ref+sops://<any-path>/vars/<group>.sops.yaml#/<key>
  match = value.match(
    /^ref\+sops:\/\/.*\/vars\/([^.]+)\.sops\.yaml#\/(.+)$/,
  );
  if (match) {
    return { group: match[1], key: match[2] };
  }

  return null;
}

/**
 * Parse any SOPS reference to extract the file path and key.
 * Works for both legacy and group-based references.
 *
 * @example
 * parseSopsReference("ref+sops://.stackpanel/secrets/dev.yaml#/DATABASE_URL")
 * // Returns: { path: ".stackpanel/secrets/dev.yaml", key: "DATABASE_URL" }
 */
export function parseSopsReference(
  value: string,
): { path: string; key: string } | null {
  const match = value.match(/^ref\+sops:\/\/([^#]+)#\/(.+)$/);
  if (!match) {
    return null;
  }
  return {
    path: match[1],
    key: match[2],
  };
}

/**
 * Extract the group name from a variable value if it's a group-based secret reference.
 * Returns the default group ("dev") if the value is not a group reference.
 */
export function getGroupFromValue(value: string, defaultGroup = "dev"): string {
  const parsed = parseGroupSopsReference(value);
  return parsed?.group ?? defaultGroup;
}

/**
 * Available secret groups for access control.
 * These correspond to SOPS files in .stackpanel/secrets/vars/
 */
export const SECRET_GROUPS = ["dev", "staging", "prod"] as const;

export type SecretGroupName = (typeof SECRET_GROUPS)[number];

/**
 * Check if a string is a valid secret group name.
 */
export function isValidSecretGroup(group: string): group is SecretGroupName {
  return (SECRET_GROUPS as readonly string[]).includes(group);
}
